#!/usr/bin/env python3
import argparse
import json
import sys
import time
from pathlib import Path

from typing import Optional

import pandas as pd
import tushare as ts


VALID_MARKETS = ("主板", "创业板", "科创板", "北交所")


def is_a_share(ts_code: str, market: str) -> bool:
    market = str(market or "")
    if not any(m in market for m in VALID_MARKETS):
        return False
    if ts_code.endswith(".SH"):
        return ts_code.startswith(("600", "601", "603", "605", "688"))
    if ts_code.endswith(".SZ"):
        return ts_code.startswith(("000", "001", "002", "003", "300", "301"))
    if ts_code.endswith(".BJ"):
        return True
    return False


def load_existing_manifest(path: Path) -> dict:
    if path.exists():
        try:
            return json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            pass
    return {
        "start_date": "",
        "end_date": "",
        "target_count": 0,
        "downloaded": 0,
        "skipped_existing": 0,
        "updated_existing": 0,
        "failed": [],
        "files": [],
    }


def latest_trade_date_from_file(path: Path) -> Optional[str]:
    if not path.exists() or path.stat().st_size <= 0:
        return None

